var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"헤헤, 이것 봐~ 역시 아이리 님이 나서면 간단하지~♪","JPN":"ヘヘ、これ見て～やっぱりアイリ様の手にかかれば簡単よ～♪","ENG":"Heh heh. Look at this. Irie can solve anything! ♪","TWN":"哈哈，看吧~~果然，艾莉一出手就知有沒有！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"일단 목숨은 건진 것 같네...... 모두 고생했어.","JPN":"とりあえず、命は助かったようだな……みんなご苦労だった。","ENG":"That was close. Everyone, good job.","TWN":"似乎是暫且保住了性命……大家都辛苦了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"적들의 전파공격이 단순한 신호방해에 그쳐서 다행이에요.","JPN":"敵の電波攻撃が単純な信号妨害程度でよかったです。","ENG":"I'm glad the enemy's electromagnetic wave attacks only jammed our signals.","TWN":"幸虧敵方的電波攻擊只是單純的信號干擾。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"이제 20분 정도면 현실세계로 부상할 수 있을 것 같아요.","JPN":"あと20分ほどすれば、ノーマルサイドに浮上できそうです。","ENG":"We've got only twenty minutes left until we'll be back into Normalside.","TWN":"大約20分鐘左右我們就能躍出至現世。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"정말이야?","JPN":"本当か？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"휴우...... 살았다......","JPN":"ふう……助かった……","ENG":"Whew, thank God!","TWN":"呼——活下來了……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"그런데 우리 싸우기 전에 말이야, 아이리와 뭘 확인해 봐야 한다고 하지 않았어?","JPN":"そうだ、戦う前にアイリと何か確認しないといけないって言ってなかったか？","ENG":"By the way, before we fought, you said Irie needed to see something. What is it?","TWN":"隊了，戰鬥前我們不是說要跟艾莉確認一下什麼的嗎?"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"응? 아이리 님 불렀어?","JPN":"何？　アイリ様を呼んだ？","ENG":"Mm? Did you call Irie?","TWN":"嗯？誰在叫艾莉？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"아, 그러고 보니......","JPN":"ああ、そういえば……","ENG":"Ah, that's right.","TWN":"啊，妳看… "},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"제나, 아이리.","JPN":"ジーナ、アイリ。","ENG":"Zena. Irie.","TWN":"珍娜、艾莉。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"혹시 이 영상 속 인물이 누군지...... 알아보겠어요?","JPN":"この映像の中の人物が誰なのか……わかりますか？","ENG":"Do you recognize this person in the video?","TWN":"妳們能夠認出...這段影片中的人物嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"이건...... 아이리잖아?","JPN":"これは……アイリじゃないか？","ENG":"It's... Irie.","TWN":"咦？這...這不是艾莉嗎?"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"응? 정말진짜? 아이리 님 언제 찍힌 거야?","JPN":"え？　本当？　アイリ様いつ撮られたの？","ENG":"Mm? It is Irie! When was Irie filmed?","TWN":"嗯？真的是耶？艾莉什麼時候拍到的？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"거기 정지! 곧 조회 시간인데 어딜 가는 거냐!","JPN":"そこ、止まれ！　もうすぐ朝礼の時間なのにどこに行くんだ！","ENG":"Hey, stop right there! It'll be a morning assembly soon. Where do you think you're going?","TWN":"停下來！就要開朝會了，妳這是要去哪裡!"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"아하하~♪ 그런 명령으론 아이리님의 스피드를 따라잡지 못할걸~♪","JPN":"あはは～♪　そんな命令ではアイリ様のスピードに追いつけないよ～♪","ENG":"Ah hah hah! ♪ Orders like that can't stop Irie! ♪","TWN":"啊哈哈哈~♪妳這種命令是追不上██大人的速度的~♪"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"몇 달만의 푸른 하늘이잖아? 이런 날 교실에 틀어박혀 있는 건 청춘에 대한 배신이라구~♪","JPN":"何か月ぶりの青空でしょ？\\nこんな日に教室に閉じこもるのは青春への裏切りだよ～♪","ENG":"I haven't seen such a blue sky for months. I'm too young to stay cooped up in a classroom on a beautiful day like this! ♪","TWN":"這麼多個月以來天空好不容易變得這麼藍，在這種日子窩在教室裡簡直背叛青春啊~~~"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"아이리 알포드...... 매일 옥상에서 학생회 허가도 받지 않고 폭죽놀이를 벌이는 무법자!","JPN":"アイリ・アルフォード……\\n毎日屋上で生徒会の許可も取らずに花火で遊ぶ無法者！","ENG":"Irie Alford. You're the outlaw who plays with fireworks every day on the rooftop, without the Student Council's permission!","TWN":"艾莉·阿爾伯特……未經學生會許可，每天在頂樓隨意施放煙火的非法之徒！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"설마...... 이번엔 선도부가 보란 듯이 교문을 지키고 있는데 땡땡이를 칠 셈인가?","JPN":"まさか……今度は風紀委員が校門を守っているのにサボる気なのか？","ENG":"Now, you're playing hooky, completely ignoring the Student Guide at the gate. Are you serious?","TWN":"難道…妳想要在先鋒部隊英勇守衛校門的時候偷懶嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"그런 건 용납할 수 없다!","JPN":"そんなことは許せない！","ENG":"That's just not done!","TWN":"不可原諒！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"앗?! 저기 UFO!","JPN":"あっ！　あれUFO！","ENG":"Look! There's a UFO!","TWN":"啊？！妳們看！有飛碟!"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"아하하, 아이리, 아무리 그래도 그런 방법에 속을 사람이 있겠어?","JPN":"あはは、アイリ。いくら何でもそんな嘘に騙される人がいるの？","ENG":"Hah hah hah. Irie, come on. You can't fool anyone like that.","TWN":"啊哈哈哈，艾莉啊，怎麼可能有人會中這招呢？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"뭐라고?! 어디에 UFO가 있다는 거지?!","JPN":"何！？ 　どこにUFOがあるんだ！？","ENG":"What? Where?!","TWN":"什麼？妳說哪裡有飛碟？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"UFO? 어디? 야옹아, 너 뭐 보여?","JPN":"UFO？　どこだ？　にゃんこちゃん、お前は何か見えるか？","ENG":"A UFO? Where? Kitty cat, can you see it?","TWN":"飛碟？在哪？小貓貓你有看到嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"멋지게 속여 넘겼다, 아이리님!","JPN":"見事に騙せたわね。さすがアイリ様！","ENG":"Good job, Irie!","TWN":"漂亮地騙過去了，艾莉！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"그럼 이만! 부르르릉~♪","JPN":"それじゃ！　ブーン～♪","ENG":"Then, ciao! Vroom, vroom! ♪","TWN":"那麼我就先走一步囉~~噗嚕噗嚕鈴~~~♪"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"큭, 당했나......!","JPN":"くっ、騙されたか……！","ENG":"Gah, she got me!","TWN":"唔，被騙了！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"야, UFO가 어디 있다는 거야? 아무것도 없는데?","JPN":"おい、どこにUFOがあるんだ？　何も見えないけど？","ENG":"Hey, where's the UFO? I don't see anything!","TWN":"喂，妳說的飛碟在哪裡呢？什麼都沒有啊。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"하지만 교칙위반은 엄중처벌! 고작 스쿠터 따위로 선도부를 따돌릴 수 있을 것 같나!","JPN":"だが校則違反は厳重に処罰しなければ！\\nスクーターなんかで風紀委員をまけると思うなよ！","ENG":"But violation of school rules is a serious transgression! Even scooters can't stop us School Council members!","TWN":"不過違反校規者將受到嚴厲的處罰！妳以為區區一台小摩托車能夠甩掉先鋒部隊嗎！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"에헤헤, 나 잡아 봐라~♪","JPN":"えへへ、捕まえてみて～♪","ENG":"Heh heh. Catch me if you can! ♪","TWN":"啊哈哈哈，來抓我呀~~"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"훗훗훗.","JPN":"ふっふっふっ。","ENG":"Hah hah hah.","TWN":"呵呵呵"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_DOOR_SF"},{"id":"L47_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"아침부터 아주 정신 없군. 그래서 더 마음에 드는 학교야.","JPN":"朝から騒がしいな。気に入った。","ENG":"It's only morning, and this place is already a mess. I love it!","TWN":"從一大早開始就很有精神呢。看來這會是一所更讓人滿意的學校吧。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"좋아. 결심했어.","JPN":"よし、決めた。","ENG":"Alright, I've made up my mind.","TWN":"好，我決定了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"이 학교, 오늘에야말로 이 풍운의 전학생 린 시엔 님이 접수해 주지!","JPN":"この学校、この風雲の転校生、リン・シエン様のものにしてやる！","ENG":"As of today, this school belongs to Lin Xien, the Stormy Transfer Student!","TWN":"就是今天，這所學校要迎接他們的風雲人物轉學生——林·西恩！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L2_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"도, 도착했습니다, 아가씨.","JPN":"と、到着しました、お嬢様。","ENG":"I-I'm here, My Lady.","TWN":"我、我們到了，大小姐！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"아, 수고했어. 아키. 학교까지 따라오느라 힘들지?","JPN":"ああ、ご苦労だったな、秋。学校までついてくるの大変だっただろう？","ENG":"Ah, good job, Aki. It's tough moving schools because of me, isn't it?","TWN":"嗯，辛苦了。秋，為了我一路跟到學校妳一定很累了吧?"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그럴 리가요! 친구들인 저희가 원해서 하는 일인걸요!","JPN":"とんでもありません！　友達の私たちが好きでやってることですし！","ENG":"Not at all! We're doing this because we want to, as your friends!","TWN":"怎麼會呢！因為這是作為朋友的我們一直期待的事情嘛，不會的！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"구, 구두를 대령할까요?","JPN":"く、靴を持ってきましょうか？","ENG":"W-would you like your loafers?","TWN":"需、需要準備皮鞋嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"아니. 아니. 아니.","JPN":"いや、いや、いや。","ENG":"No. No. No.","TWN":"不用，不用，不用。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"파릇한 청춘들이 열심히 뛰노는 모습을 보니 나도 흥이 돋는군. 훗훗훗.","JPN":"元気な若者たちが元気に遊び回る姿を見ると興が乗ってくるな。ふっふっふっ。","ENG":"Watching those youngsters run around and play with each other, I'd like to do the same. Hah hah hah.","TWN":"看到青春少年們努力奔跑的模樣，我也興致高昂了起來呢，呵呵呵。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"오늘은 운동화로 부탁해.","JPN":"今日はスニーカーで頼む。","ENG":"I want my running shoes today.","TWN":"今天就準備運動鞋吧。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"떠나는 기념으로 조촐한 이벤트를 준비해 뒀거든.","JPN":"ここを去る記念に小さなイベントを用意したからな。","ENG":"I've prepared a small event to celebrate my departure.","TWN":"為了紀念離開的日子，我準備了一個小活動。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"여기 있습니다!","JPN":"ここにあります！","ENG":"There you are!","TWN":"就是這個！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"어라? 신발이 조금 헐렁한 것 같은데?","JPN":"あれ？　靴が少し緩いようだが？","ENG":"Err? These shoes are a little big.","TWN":"嗯？這鞋子好像有點大了？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"앗? 마, 많이 불편하신가요?","JPN":"あっ！　ご、ご不便ですか？","ENG":"Ah? A-are they too big?","TWN":"啊？不、不合腳嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"엥?","JPN":"え？","ENG":"Huh?","TWN":"嗯？？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"아니, 괜찮아. 이럴 때를 대비해서 교실까지 전용 무빙워크를 설치해 뒀거든.","JPN":"いや、いいんだ。こういう時に備え、教室まで専用ムービングウォークを設置しておいたから。","ENG":"No, don't worry. I've had a special moving walkway installed all the way to my classroom for situations like this.","TWN":"不，沒關係。為了應對這種情況，我設置了前往教室的自動步道。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그, 그러니까 불편하시다는 거죠?","JPN":"つ、つまりご不便ということですよね？","ENG":"S-so they're not comfortable.","TWN":"所、所以您的腳很不舒服吧？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"다리라도 주물러 드릴까요?","JPN":"脚でもマッサージしましょうか？","ENG":"Would you like me to rub your legs?","TWN":"要不幫您按摩一下？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"괜찮아, 친구들!","JPN":"いいんだ、友よ！","ENG":"Don't worry, friends!","TWN":"不要緊的啦，我的朋友們！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"나 린 시엔, 실수를 빌미로 친구를 내치는 매몰찬 인간이 아니야.","JPN":"私、リン・シエン。失敗を理由に友達を突き放すような冷酷な人間じゃない。","ENG":"Lin Xien is not so cruel that she gets rid of her friends for a small mistake like this.","TWN":"我林·西恩，不是那種因為失誤就趕走朋友的冷酷之人。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"우리가 눈 덮인 설원에서 함께 겪었던 그 뜨거운 우정의 시간들을 떠올려 봐!","JPN":"雪に覆われた雪原で共に過ごした、あの熱い友情の時間を思い出してみろ！","ENG":"Think about our precious time together in that snowfield.","TWN":"快回想我們在白雪覆蓋的雪原上，一同度過的那段充滿熱血友情的時光吧！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"......눈? 설원? 저희가 그런 곳을 갔었나요?","JPN":"……雪？　雪原？　そんな所に行きましたっけ？","ENG":"Snowfield? Precious time? Have we been in a snowfield?","TWN":"雪.....？雪原？我們去過這樣的地方嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"런칭 안 된 이벤트 얘기 같은데요......","JPN":"まだ未実装のイベントだと思いますが……","ENG":"I think she's talking about an event that hasn't been released...","TWN":"說的好像是那個最終沒辦成的活動？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"미구현 에피소드 같은 거 언제 기획이 뒤집힐지 모르는 걸요......","JPN":"未実装イベントだと、いつ企画がひっくり返るかわかりませんよ……","ENG":"Unimplemented episodes can be scrapped anytime...","TWN":"這種像是遊戲未實裝的劇情，企劃什麼時候會被作廢都不知道..."},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"훗. 그럼 이제 교실로 가야겠군.","JPN":"ふっ。では、教室に向かおうか。","ENG":"Heh. Now, I'm going to go to my classroom.","TWN":"嗯，那我該去教室了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"이 전대미문의 전학생 린 시엔님을 하루밖에 품지 못하다니, 정말이지 불행한 학교라니까.","JPN":"この前代未聞の転校生リン・シエン様と一日しか過ごせないなんて、本当に不幸な学校だな。","ENG":"I feel sorry for this school. It only gets to keep this legendary transfer student, Lin Xien, for a day.","TWN":"竟然連一天都沒辦法容下我這個前所未聞的轉學生林·西恩，這真是一所不幸的學校。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"저...... 어제도 그제도 학교 나왔는데......","JPN":"あの……昨日も一昨日も登校しましたが……","ENG":"Err... You were here yesterday... and the day before that...","TWN":"這個…妳昨天也是這樣說的走出學校…"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"쉿, 쉿!","JPN":"シッ、シッ！","ENG":"Shhh!","TWN":"噓！噓！！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"으브븝!","JPN":"ううっ！","ENG":"Mmmff!","TWN":"噢！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"그럼 수업 듣는 동안 차 관리 잘 부탁해?","JPN":"それじゃ、授業受けている間に車の管理、頼んだぞ？","ENG":"Now, please take good care of my car while I'm in class.","TWN":"那在我上課的時候，車輛管理就交給妳們囉？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"친구들의 끝내 주는 일처리, 기대하고 있겠어!","JPN":"友達の最高の仕事ぶり、期待してるからな！","ENG":"I'll be counting on you, my friends.","TWN":"朋友完美解決問題的方法啊，嗯，真令人期待啊。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"아, 알겠습니다!","JPN":"わ、わかりました！","ENG":"Yes, My Lady!","TWN":"啊，好的！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"거, 걱정마세요. 하교할 때는 먼지가 미끄러질 정도로 박박 닦아놓을게요!","JPN":"ご、ご心配なく。下校する頃にはほこりが滑るくらいに拭いておきます！","ENG":"D-don't worry. It'll be sparkling clean by the time you're out of school.","TWN":"放心，到了放學的時候，我們會幫妳把車擦得一塵不染的！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"고맙네, 친구들. 자네들을 볼 때마다 아직 강호의 도리가 살아있음을 느끼게 되는군.","JPN":"ありがとう、友よ。お前たちを見るたび、江湖の道義がまだ生きていることを感じるよ。","ENG":"Thank you, friends. Every time I see you, you remind me that the moral tenets of Jianghu are still well-respected.","TWN":"謝謝，我的朋友們。每次看到妳們，我就感覺到江湖義氣還是存在著。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그럼요! 다녀오세요!","JPN":"ありがとうございます！　いってらっしゃいませ！","ENG":"Absolutely! See you later!","TWN":"當然！等妳回來！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"프, 프리덤 라이더즈 파이팅!","JPN":"ふ、フリーダム・ライダーズ、ファイト！","ENG":"F-Freedom Riders, rule!","TWN":"自...自由騎士，加油！！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"어쩌다 이렇게 된 걸까요......","JPN":"どうしてこんなことになったのでしょう……","ENG":"How did this happen?","TWN":"事情為什麼會變成這樣..."},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"크흑! 돈이 필요하다고 하지 말고 더 단도직입적으로 말해야 했어요!","JPN":"くうう！　お金が必要だなんて言わずに、もっと単刀直入に話すべきだったんです！","ENG":"*Sniffle* We should have been more direct instead of saying we needed money.","TWN":"討厭！早知就不要說缺錢，應該要把情況更直截了當地說出來啊！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"설마하니 급전이 필요하다니까 일자리를 알선해 줄 줄이야......","JPN":"急にお金が必要になったって言ったら、まさか仕事を紹介されるなんて……","ENG":"This is what she did, giving us a job when we said we needed money in a hurry.","TWN":"沒想到竟然會幫我們介紹工作…"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"왜 이런 부분만 정상인의 사고방식이죠?! 교문부터 교실까지 무빙워크 타고 가는 사람이?!","JPN":"どうしてこんな時だけ正常な人の考え方するんですか！？\\n校門から教室までムービングウォークに乗るような人が！","ENG":"How can she be so normal in certain aspects? She's the type who installs a moving walkway from the school gate to her classroom!","TWN":"為什麼她只有在這種時候會是正常人的思考方式啊？那個從校門到教室搭乘自動步道的傢夥?!"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"흑...... 많이도 필요 없는데...... 평생 나 혼자 탱자탱자 놀고 먹을 돈만 현찰로 뚝 떼서 주면 되는데......","JPN":"ぐすっ……多くは要らないのに……\\n私だけでいいから一生遊んで暮らせる分だけ現金でくれればいいのに……","ENG":"*Sob* I didn't ask for a lot of money, either. I just needed some cash, enough to last me for the rest of my life...","TWN":"唔....也不用太多....那一點錢就夠我一輩子吃喝玩樂了...."},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"히로세 씨......","JPN":"廣瀬さん……","ENG":"Ms. Hirose...","TWN":"廣瀨小姐……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"인성 깎아 먹는 발언은 그만하고 걸레질이나 어서 도와 주세요......","JPN":"人間性を疑うような発言はそこまでにして、雑巾がけでも手伝ってください……","ENG":"Stop being so pitiful and come help me wipe the car.","TWN":"不要再說這些沒義意的話了，快來幫我一起擦吧..."},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"2인용 컨트롤러 꽂아 놓고 혼자 게임 하는 기분이에요......","JPN":"コントローラーを2つ繋げて、一人でゲームしてるような気分です……","ENG":"I feel as if I'm playing two-player mode by myself.","TWN":"我現在感覺像是在用兩人遊戲搖捍，但自己和自己玩遊戲一樣..."},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"히엑?!","JPN":"ひいっ！？","ENG":"Heek!","TWN":"呃？！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_TANK_DAMAGE_DOWN"},{"id":"L8_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"아앗! 또 사이드 미러가 떨어졌어?!","JPN":"あっ！　またサイドミラーが落ちちゃった！？","ENG":"Wah! The side view mirror fell again!","TWN":"啊！旁邊的鏡子又掉下來了！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"분명 저번에 부서졌을 때 접착제로 제대로 붙여 뒀는데!","JPN":"この前落ちた時、接着剤でしっかりくっつけたはずなのに！","ENG":"I glued it when it broke off the last time!","TWN":"上次掉下來的時候，明明已經用膠水黏好了啊！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"큭, 아이리 녀석! 방패를 안 든 상태에선 잽싸군!","JPN":"くっ、アイリのやつ！　盾を持たない状態だとすばしっこいな！","ENG":"Gah, Irie girl! You're pretty fast without your shield!","TWN":"哼，艾莉這傢夥！手裡不拿著盾牌的時候真是敏捷啊。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"에헤헷♪ 선도부장님이 둔해진 거 아냐?","JPN":"えへへっ♪　風紀委員長がとろいだけじゃなくて？","ENG":"Heh heh heh. ♪ You're probably just too slow, Student Guide Leader.","TWN":"啊哈哈哈，這先鋒部隊長是不是變遲鈍了？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"사실 난 알고 있지롱♪ 선도부실에서 누가 들어올까 눈치 살피면서 무지무지 달아 보이는 케이크를 혼자 냠냠했다거나♪","JPN":"アイリ様は知ってるんだよね♪\\n風紀委員会室で誰か入ってこないか警戒しながら、超甘そうなケーキを一人でもぐもぐ食べたこととか♪","ENG":"I know things about you that others don't know. ♪ You sometimes eat delicious cake when you're alone in the Student Guide Room, thinking no one's there to see you. ♪","TWN":"其實我都知道呢~~♪在先鋒部隊室裡，妳都會小心翼翼地提防有沒有人進來，一邊大口大口地把奶油蛋糕塞進嘴裡呢哈哈哈哈♪"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"유, 유언비어 유포는 즉결 처분이다!","JPN":"で、デマを流した者は即決処分だぞ！","ENG":"Those s-spreading rumors are subject to summary justice!","TWN":"妳…妳散播不實謠言，需要立刻受到處分！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"가자, 버고 소드! 교칙은 우리에게 있다!","JPN":"行くぞ、ヴァルゴソード！　校則は私たちが守らねば！","ENG":"Let's go, Virgo Sword! We must protect the school rules!","TWN":"走吧，我的布林加夫之劍，告訴他們這裡可是有校規的！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HYPER_ATTACK_START"},{"id":"L19_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"유진아! 에스텔 말리는 것 좀 도와 줘!","JPN":"シロコ！　一緒にエステルを止めてちょうだい！","ENG":"Eujin! Help me stop Esther!","TWN":"劉珍！快來幫我解決這東西！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"진정해, 선도부장! 우리의 추억이 깃든 학교를 몽땅 산화시킬 셈이야?!","JPN":"落ち着け、風紀委員長！　俺たちの思い出の学校を粉々にする気か！？","ENG":"Calm down, Student Guide Leader! You're going to destroy our school, along with our precious memories of it!","TWN":"冷靜點，先鋒部隊長！難道妳真的要把我們記憶中充滿各種回憶的學校，全都被你給氧化掉嗎？！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"훗.","JPN":"ふっ。","ENG":"Heh.","TWN":"呼。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"안녕하신가, 학우 여러분.","JPN":"よお、学友ども。","ENG":"Hello, my fellow students.","TWN":"早上好啊，同學們。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"아침부터 무척 활기차 보이는군. 덕분에 나까지 그만 들뜬 기분이 들었지 뭐야.","JPN":"朝から元気いっぱいじゃないか。おかげでこちらまで浮かれてしまうな。","ENG":"I see that you're having an energetic morning. And your mood is very contagious.","TWN":"一大早妳們就如此朝氣蓬勃，連我看了也跟著興奮起來了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"그 마음에 부응하고자, 비장의 이벤트를 준비했지!","JPN":"この雰囲気に応えようと、とっておきのイベントを用意したぞ！","ENG":"In response, I've prepared a special event!","TWN":"為了回應大家的熱情，我特別準備了一個盛大的活動！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"숨겨서 무엇하랴! 지금 나의 파트너와 함께 공개해 주마!","JPN":"隠していてもしょうがない！　私のパートナーと一緒に見せてやろう！","ENG":"I don't want to hide it anymore! Let me and my partner show it to you now!","TWN":"我就不繼續賣關子！現在就來和我的夥伴一同揭曉吧！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"시엔! 뒤로 물러서!","JPN":"シエン！　下がって！","ENG":"Xien! Step back!","TWN":"西恩！妳快退後！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"무슨 소리야, 반장.","JPN":"何言ってるんだ、委員長。","ENG":"What are you talking about, Class President?","TWN":"妳在說什麼啊，班長？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"이 린 시엔님은 학교에 파란을 몰고 올 전학생! 여기서 물러설 쏘냐!","JPN":"このリン・シエン様は学校に波乱を起こす転校生！\\nここで引き下がるものか！","ENG":"I'm the transfer student destined to stir up this school. No way I'm going to step back!","TWN":"我林·西恩大人是我們學校的風雲轉學生！怎麼能在這裡退後！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"쟨 또 갑자기 왜 저런대?! 원래는 반장과의 의리니 뭐니 하면서 말 잘 듣지 않았어?","JPN":"あいつどうしたんだ！？　委員長との義理とかで言うことはよく聞いてただろ？","ENG":"What's wrong with her all of a sudden? She used to always listen to the Class President, talking about loyalty and whatnot.","TWN":"這又怎麼了？！ 西恩跟班長間可沒有什麼義理互相幫助啊？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"어제 밤에 학원물 드라마 보다가 컨셉이 이상하게 섞였나 봐!","JPN":"昨晩学園ドラマを見たせいで、コンセプトが変に混ざっちゃったみたい！","ENG":"She must have gotten her themes mixed up, after watching a school show last night.","TWN":"看來在這最後的夜晚摻雜了比校園連續劇還要複雜的元素。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"어차피 언젠가 서로 반장 자리를 두고 겨룰 처지......","JPN":"どうせいつかは委員長の座をかけて競う者同士……","ENG":"Sooner or later, we'll be competing over the Class President position.","TWN":"反正總有一天，我們會為了班長的職位而一決勝負……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"한 반에 두 명의 정상은 필요 없는 법!","JPN":"一つのクラスにトップは二人も要らない！","ENG":"No class needs two presidents!","TWN":"一個班不需要兩個班長！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"원한다면, 여기서 결판을 내 보도록 하실까!","JPN":"望むなら、ここで決着をつけようじゃないか！","ENG":"We'll decide who deserves it right here and now!","TWN":"我們就在這裡分出高下吧！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"거기 서 있다간 휩쓸린다니까!","JPN":"そこに立ってたら飛ばされちゃうってば！","ENG":"Don't just stand there—you'll get swept away!","TWN":"妳站在那裡會被波及到的！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"엥?","JPN":"えぇ？","ENG":"Huh?","TWN":"嗯？？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"파도쳐라, 섬과아아아앙!!","JPN":"うなれ、閃光！！！！","ENG":"Surge, Flash!","TWN":"閃閃吧，閃～～～光！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"우와~♪","JPN":"うわぁ～♪","ENG":"Whoa! ♪","TWN":"哇啊~♪"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"얘들아~ 아이리님 부웅 날고 있어~","JPN":"みんな～アイリ様がブーンって飛んでるよ～！","ENG":"Guys, look! Irie's flying!","TWN":"各位~ 艾莉正在飛呢~~"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"아, 집사. 저번에 뽑은 조종사 있지?","JPN":"もしもし、執事か。この前雇ったパイロットがいるだろ？","ENG":"Ah, Butler. You know the pilot we hired a while ago.","TWN":"喂，管家，上次選拔出來的駕駛員還在吧?"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"아니, 등교하자마자 하교하게 되서. 전용기 좀 준비해 줘.","JPN":"いや、登校してすぐ下校することになった。専用機を用意してくれ。","ENG":"No. I just came to school, but have to leave already. Get my jet ready.","TWN":"沒事，只是因為才剛上學就立刻放學了，請幫我準備專機。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"에이, 땡땡이 아냐. 폭발에 휘말려서 날아가는 중이거든. ......응, 알았어. 끊어.","JPN":"違う、さぼりじゃない。爆発に巻き込まれて飛ばされてるんだ。\\n……うん、わかった。切るぞ。","ENG":"No, I'm not playing hooky. I got caught up in an explosion, and now I'm airborne. ... Okay, okay. Let's hang up.","TWN":"欸咦？我沒有偷懶，我是因為一場爆炸而飛上天了…… 好，我知道了，我掛斷了。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"......훗!","JPN":"……ふっ！","ENG":"Heh!","TWN":"....呼！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"이번에는 순순히 물러나지만 다음에는 인륜을 등지고 상대해 주지, 반장.","JPN":"今回は引き下がるが、次は倫理など考えずに相手してやろう、委員長。","ENG":"I'll leave you alone this time, but I will transgress moral laws if I must to beat you next time, Class President.","TWN":"這次我就乖乖退出吧，但下一次我會不擇手段的，班長！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"지금은 그저, 내 칠흑의 송곳니들이 너에게 향하는 날이 오지 않기를 바랄 뿐......","JPN":"今はただ、私の漆黒の牙がお前に向く日が来ないことを願うばかり……","ENG":"For now, pray that my fangs of darkness won't be bared at you anytime soon.","TWN":"妳現在就期望我的漆黑獠牙咬向妳的那一天永遠不會到來吧……"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"시엔도 오늘 땡땡이야?","JPN":"シエンも今日はさぼり？","ENG":"Xien, are you also cutting class today?","TWN":"西恩今天也蹺課了嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"역시 아이리님! 귀여움으로 땡땡이도 1+1 만들어 버렸어! 얼마나 대단한 거야~♪","JPN":"さすがアイリ様！　可愛さでさぼりもおまけ付きにできちゃったわ！\\nほんとすご～い♪","ENG":"Irie's so amazing! She's so cute that people want to play hooky with her. She's incredible! ♪","TWN":"不愧是艾莉。啊哈哈哈哈，又可愛又會蹺課，多麼了不起啊~♪"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"덤 취급하는 듯한 말은 그만둬!","JPN":"おまけ扱いするような言い方はやめろ！","ENG":"Stop. I'm not here for you!","TWN":"別那再說這種蠢話了！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"아야야......","JPN":"いたたっ……","ENG":"Ouch!","TWN":"哎呀呀...."},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L27_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"하구구야......","JPN":"あううっ……","ENG":"Aww...","TWN":"哎呀..."},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"엄청 멀리 날아와 버린 것 같은데......","JPN":"かなり遠くまで飛ばされてしまったようだが……","ENG":"I think we've flown pretty far away.","TWN":"好像真的飛得很遠了..."},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"진짜? 너무 늦게 돌아가면 시간에 못 맞출 텐데~","JPN":"本当？　帰るのが遅くなっちゃうと間に合わないと思うんだけど～。","ENG":"Really? But I want to go back before it's too late.","TWN":"真的嗎？如果太晚回去的話，時間肯定會趕不上的！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"훗. 염려 붙들어 매시라. 전용기를 타고 가면 금방이란 말씀.","JPN":"ふっ。心配無用だ。専用機に乗ればすぐだからな。","ENG":"Heh. Don't worry. We can take my jet to go back in a jiffy.","TWN":"哼，妳就安下心吧。坐專機很快的。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"으힉?! 침식체!","JPN":"うわっ！？　侵食体！","ENG":"Heek! C.O.!","TWN":"咿？這是、侵蝕體？！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"비스트들이 엄청 우글거려. 우리 위상 방벽 밖까지 날아왔나 봐.","JPN":"ビーストがうじゃうじゃいるわ。位相防壁の外まで飛んできたみたい。","ENG":"We're surrounded by Beasts. We must have flown outside the phase barrier.","TWN":"那些野獸們真纏人呢…我猜它們從我們的相位屏障外繞過去了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"아이리님이랑 시엔이랑 신기록 세웠어! 굉장하다♪ 그치?","JPN":"アイリ様とシエンが新記録を立てたわね！　すご～い♪　でしょ？","ENG":"Irie and Xien have made a new record! We're so great, aren't we? ♪","TWN":"艾莉和西恩大人創造了新紀錄！太棒了♪ 是吧！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"그, 그래?","JPN":"そ、そうか？","ENG":"S-sure...","TWN":"咦，是、是啊？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"훗...... 역시 전학생, 가는 곳마다 최고가 되어버리는군.","JPN":"ふっ……さすが転校生だ。行く先々で最高になっちゃうんだよな。","ENG":"Heh. I'm the unbeatable transfer student wherever I go.","TWN":"哇…不愧是傳奇的轉學生，什麼都拿第一。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"이 거침없는 행보의 끝은 어디서 끝날 것인가!","JPN":"この堂々たる歩みはどこで終わるのだろうか！","ENG":"Where will my inexorable journey end?","TWN":"這趟通行無阻的旅行最終會到達何處呢？~"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L44_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"저 침식체 우리한테 달려 오는데? 여기서 끝내려나 봐♪","JPN":"あの侵食体、こっちに向かって走ってきてるよ？　ここで終わるみたい♪","ENG":"That C.O. is charging at us. I think your journey will end here. ♪","TWN":"那個侵蝕體朝我們過來了。看來...你這趟通行無阻的旅行就要到此結束了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"얼른 스쿠터 시동 걸어!! 작전상 후퇴다!!","JPN":"早くスクーターのエンジンをかけろ！！　ひとまず後退だ！！！","ENG":"Start your scooter now! We're making a strategic retreat!","TWN":"快！！！發動機車!! 戰術性撤退!!"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};